section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/trunk-based-dev-principles.json",
  "type": "object",
  "required": ["artefact_id", "repo_ref", "principles", "total", "verdict", "version", "last_reviewed"],
  "properties": {
    "artefact_id": {"type": "string", "pattern": "^tbd-[a-z0-9-]{6,}$"},
    "repo_ref":    {"type": "string", "minLength": 1},
    "principles": {
      "type": "object",
      "required": ["single_trunk", "small_commits", "releasable_trunk", "fast_ci"],
      "properties": {
        "single_trunk": {
          "type": "object",
          "required": ["score", "evidence"],
          "properties": {
            "score":    {"type": "integer", "minimum": 0, "maximum": 25},
            "evidence": {"type": "string", "description": "count of branches > 2 days old, branch policy reference"}
          }
        },
        "small_commits": {
          "type": "object",
          "required": ["score", "evidence"],
          "properties": {
            "score":    {"type": "integer", "minimum": 0, "maximum": 25},
            "evidence": {"type": "string", "description": "median PR LoC, median branch age"}
          }
        },
        "releasable_trunk": {
          "type": "object",
          "required": ["score", "evidence"],
          "properties": {
            "score":    {"type": "integer", "minimum": 0, "maximum": 25},
            "evidence": {"type": "string", "description": "auto-revert presence, flag inventory non-empty, gate composition"}
          }
        },
        "fast_ci": {
          "type": "object",
          "required": ["score", "evidence"],
          "properties": {
            "score":    {"type": "integer", "minimum": 0, "maximum": 25},
            "evidence": {"type": "string", "description": "p50 CI duration, p95 CI duration"}
          }
        }
      }
    },
    "total":    {"type": "integer", "minimum": 0, "maximum": 100},
    "verdict":  {"enum": ["adopt", "partial-adopt", "not-ready"]},
    "fixes": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["principle", "issue", "suggested_fix"],
        "properties": {
          "principle":     {"type": "string"},
          "issue":         {"type": "string"},
          "suggested_fix": {"type": "string"}
        }
      }
    },
    "version":       {"type": "string", "pattern": "^\\d+\\.\\d+\\.\\d+$"},
    "last_reviewed": {"type": "string", "format": "date"}
  }
}

example.code:
{
  "artefact_id": "tbd-myrepo-2026-05",
  "repo_ref": "github.com/org/myrepo",
  "principles": {
    "single_trunk":      {"score": 24, "evidence": "0 branches > 2 days, BRANCHING.md present"},
    "small_commits":     {"score": 22, "evidence": "median PR 142 LoC, median branch age 11h"},
    "releasable_trunk":  {"score": 20, "evidence": "auto-revert on, 14 active flags, lint+typecheck+test+coverage gates"},
    "fast_ci":           {"score": 18, "evidence": "p50 6m12s, p95 9m48s"}
  },
  "total": 84,
  "verdict": "adopt",
  "fixes": [],
  "version": "1.0.0",
  "last_reviewed": "2026-05-23"
}
